def generate_hash(password):
    salt = b'$2a$12$SaltKey'
    return hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)

def check_password(stored_hash, submitted_hash):
    salt = stored_hash[:58]
    stored_hash = stored_hash[58:]
    return hashlib.pbkdf2_hmac('sha256', submitted_hash.encode(), salt, 100000) == stored_hash

